        activateAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{5}{R/P}: Transform");
        addTarget(playerA, GEARHULK); // beginning of combat trigger

        setStrictChooseMode(true);
        setStopAt(1, PhaseStep.DECLARE_ATTACKERS);
        execute();

        assertPermanentCount(playerA, GEARHULK, 1);
        assertGraveyardCount(playerA, GEARHULK, 0);
